  if (spawnSync("which", ["git"], { stdio: "ignore" }).status !== 0) return {}
  const email = spawnSync("git", ["config", "--global", "user.email"], { encoding: "utf8" })
  const remote = spawnSync("git", ["remote", "get-url", "origin"], { encoding: "utf8" })
