  try { unlinkSync(`${base}.pub`) } catch {}
}

function isCommandAvailable(cmd: string): boolean {
  const lookup = process.platform === "win32" ? "where" : "which"
  return spawnSync(lookup, [cmd], { stdio: "ignore" }).status === 0
}
