    }
    process.stderr.write("Usage: sshx agent <list|add|remove> [key]\n")
    process.exit(1)
  }

  if (command === "setup") {
    const { flags, rest: setupRest } = parseFlags(rest)
    const providerArg = setupRest[0]
    if (!providerArg) {
      process.stderr.write("Usage: sshx setup <provider> [opts]\n")
