+      : ["-t", "ed25519", "-C", email, "-f", keyPath, "-N", ""];
+
+  const result = spawnSync("ssh-keygen", args, { stdio: "inherit", encoding: "utf8" });
+  if (result.error) {
+    throw result.error;
+  }
+
+  if ((result.status ?? 1) !== 0) {
+    throw new Error("ssh-keygen failed.");
+  }
+}
