  }

  generateKey(options.provider, options.email, options.keyName);

  try {
    upsertHostBlock(options.provider, host, options.keyName);
  } catch (error) {
    deleteKeyFiles(options.keyName);
    throw error;
  }

  addToAgent(options.keyName);

  if (!options.noGitConfig) {
    try {
      configureGitForKey(options.keyName, host, options.email);
    } catch {
      // Non-fatal: setup should still complete if git config is unavailable.
    }
  }

  const publicKey = readPublicKey(options.keyName);
  const clipboardCopied = !options.noClipboard && copyToClipboard(publicKey);
  const browserOpened = !options.noBrowser && openInBrowser(PROVIDERS[options.provider].settingsUrl);

  return {
    keyName: options.keyName,
    host,
    publicKey,
    clipboardCopied,
    browserOpened,
  };
}

function addToAgent(keyName: string): void {
  if (!commandExists("ssh-add")) {
    return;
  }

  ensureAgent();
  const keyPath = join(SSH_DIR, keyName);
  const args = detectPlatform() === "macos" ? ["--apple-use-keychain", keyPath] : [keyPath];
  const result = spawnSync("ssh-add", args, { encoding: "utf8" });

  if (result.status !== 0) {
    spawnSync("ssh-add", [keyPath], { encoding: "utf8" });
  }
}

function ensureAgent(): void {
  if (detectPlatform() === "windows") {
    return;
  }

  if (process.env.SSH_AUTH_SOCK) {
    return;
  }

  if (!commandExists("ssh-agent")) {
    return;
  }

  const result = spawnSync("ssh-agent", ["-s"], { encoding: "utf8" });
  if (result.status !== 0) {
    return;
  }

  for (const match of (result.stdout ?? "").matchAll(/(\w+)=([^;]+);/g)) {
    process.env[match[1]] = match[2];
  }
}

function configureGitForKey(keyName: string, host: string, email: string): void {
  if (!commandExists("git")) {
    return;
  }

  const gitConfigPath = join(SSH_DIR, `.gitconfig-${keyName}`);
  writeFileSync(gitConfigPath, `[user]\n    email = ${email}\n`);

  const includeKeys = [
    `includeIf.hasconfig:remote.*.url:git@${host}:*/**.path`,
    `includeIf.hasconfig:remote.*.url:ssh://git@${host}/**.path`,
  ];

  for (const includeKey of includeKeys) {
    spawnSync("git", ["config", "--global", includeKey, gitConfigPath], { encoding: "utf8" });
  }
}

function readGitConfigValue(key: string): string | undefined {
  if (!commandExists("git")) {
    return undefined;
  }

  const localResult = spawnSync("git", ["config", key], { encoding: "utf8" });
  if (localResult.status === 0 && localResult.stdout.trim()) {
    return localResult.stdout.trim();
  }

  const globalResult = spawnSync("git", ["config", "--global", key], { encoding: "utf8" });
  if (globalResult.status === 0 && globalResult.stdout.trim()) {
    return globalResult.stdout.trim();
  }

  return undefined;
}

export function readGitContext(): GitContext {
  if (!commandExists("git")) {
    return {};
  }

  const remoteResult = spawnSync("git", ["remote", "get-url", "origin"], { encoding: "utf8" });
  const remoteUrl = remoteResult.status === 0 ? remoteResult.stdout.trim() : undefined;

  return {
    email: readGitConfigValue("user.email"),
    remoteUrl,
    provider: remoteUrl ? detectProviderFromRemoteUrl(remoteUrl) : undefined,
  };
}

import { describe, expect, it } from "bun:test";
import {
  SSHX_MARKER,
  buildHostBlock,
  extractHostName,
  extractIdentityFiles,
  parseConfigSegments,
  serializeConfigSegments,
} from "./config";

describe("parseConfigSegments", () => {
  it("returns empty array for empty input", () => {
    expect(parseConfigSegments("")).toEqual([]);
    expect(parseConfigSegments("   \n  ")).toEqual([]);
  });

  it("parses a single unmanaged host block", () => {
    const input = `Host github.com
  HostName github.com
  User git
  IdentityFile ~/.ssh/id_ed25519`;

    expect(parseConfigSegments(input)).toEqual([
      {
        kind: "host",
        host: "github.com",
        managed: false,
        lines: input.split("\n"),
      },
    ]);
  });

  it("parses a managed host block with a standalone marker line", () => {
    const input = `${SSHX_MARKER}
Host github.com
  HostName github.com
  User git`;

    expect(parseConfigSegments(input)[0]).toMatchObject({
      kind: "host",
      host: "github.com",
      managed: true,
    });
  });

  it("still recognizes the legacy inline marker syntax", () => {
    const input = `Host my-alias  # sshx
  HostName github.com`;

    expect(parseConfigSegments(input)[0]).toMatchObject({
      kind: "host",
      host: "my-alias",
      managed: true,
    });
  });

  it("preserves leading text segments", () => {
    const input = `# Global SSH config
ServerAliveInterval 60

Host github.com
  User git`;

    const result = parseConfigSegments(input);
    expect(result[0]).toMatchObject({ kind: "text" });
    expect(result[1]).toMatchObject({ kind: "host", host: "github.com" });
  });

  it("parses multiple host blocks", () => {
    const input = `${SSHX_MARKER}
Host github.com
  IdentityFile ~/.ssh/id_github

${SSHX_MARKER}
Host bitbucket.org
  IdentityFile ~/.ssh/id_bb`;

    const result = parseConfigSegments(input);
    expect(result).toHaveLength(2);
    expect(result[0]).toMatchObject({ host: "github.com", managed: true });
    expect(result[1]).toMatchObject({ host: "bitbucket.org", managed: true });
  });
});

describe("serializeConfigSegments / round-trip", () => {
  it("round-trips a config with text and host blocks", () => {
    const input = `# comment

${SSHX_MARKER}
Host github.com
  HostName github.com
  User git
  IdentityFile ~/.ssh/id_ed25519_github`;

    const segments = parseConfigSegments(input);
    const output = serializeConfigSegments(segments);

    expect(output).toContain(SSHX_MARKER);
    expect(output).toContain("Host github.com");
    expect(output).toContain("IdentityFile ~/.ssh/id_ed25519_github");
  });
});

describe("extractIdentityFiles", () => {
  it("extracts IdentityFile values from lines", () => {
    const lines = [
      "Host github.com",
      "  HostName github.com",
      "  IdentityFile ~/.ssh/id_ed25519",
      "  IdentityFile ~/.ssh/backup_key",
    ];

    expect(extractIdentityFiles(lines)).toEqual([
      "~/.ssh/id_ed25519",
      "~/.ssh/backup_key",
    ]);
  });

  it("strips wrapping quotes", () => {
    expect(extractIdentityFiles(['  IdentityFile "~/.ssh/my key"'])).toEqual(["~/.ssh/my key"]);
  });
});

describe("extractHostName", () => {
  it("extracts HostName from lines", () => {
    expect(extractHostName(["Host alias", "  HostName github.com", "  User git"])).toBe("github.com");
  });

  it("returns empty string when no HostName exists", () => {
    expect(extractHostName(["Host github.com"])).toBe("");
  });
});

describe("buildHostBlock", () => {
  it("writes a standalone marker line for managed blocks", () => {
    const lines = buildHostBlock("github", "github.com", "id_ed25519_github");
