export type ProviderKey = "bitbucket" | "github" | "gitlab" | "azure";

export type Provider = {
  label: string;
  hostname: string;
  settingsUrl: string;
  keyType: "ed25519" | "rsa";
};

export const PROVIDERS: Record<ProviderKey, Provider> = {
  github: {
    label: "GitHub",
    hostname: "github.com",
    settingsUrl: "https://github.com/settings/keys",
    keyType: "ed25519",
  },
  gitlab: {
    label: "GitLab",
    hostname: "gitlab.com",
    settingsUrl: "https://gitlab.com/-/profile/keys",
    keyType: "ed25519",
  },
  bitbucket: {
    label: "Bitbucket",
    hostname: "bitbucket.org",
    settingsUrl: "https://bitbucket.org/account/settings/ssh-keys/",
    keyType: "ed25519",
  },
  azure: {
    label: "Azure DevOps",
    hostname: "ssh.dev.azure.com",
    settingsUrl: "https://dev.azure.com/_usersSettings/keys",
    keyType: "rsa",
  },
};

export const PROVIDER_KEYS = Object.keys(PROVIDERS) as ProviderKey[];

export function detectProviderFromHostname(hostname: string): ProviderKey | undefined {
  for (const [key, provider] of Object.entries(PROVIDERS) as [ProviderKey, Provider][]) {
    if (hostname.includes(provider.hostname)) {
      return key;
    }
  }

  return undefined;
}

export function detectProviderFromRemoteUrl(url: string): ProviderKey | undefined {
  if (url.includes("github.com")) {
    return "github";
  }

  if (url.includes("gitlab.com")) {
    return "gitlab";
  }

  if (url.includes("bitbucket.org")) {
    return "bitbucket";
  }

  if (url.includes("dev.azure.com") || url.includes("vs-ssh.visualstudio.com")) {
    return "azure";
  }

  return undefined;
}

export function normalizeProviderKey(value: string): ProviderKey | undefined {
  const normalized = value.trim().toLowerCase();

  if (normalized === "github" || normalized === "gh") {
    return "github";
  }

  if (normalized === "gitlab" || normalized === "gl") {
    return "gitlab";
  }

  if (normalized === "bitbucket" || normalized === "bb") {
    return "bitbucket";
  }

  if (normalized === "azure" || normalized === "azure-devops" || normalized === "azuredevops") {
    return "azure";
  }

  return undefined;
}

import { existsSync, readFileSync, unlinkSync } from "node:fs";
import { join } from "node:path";
import { spawnSync } from "node:child_process";
import { type ProviderKey, PROVIDERS } from "../providers";
import { commandExists } from "../platform";
import { SSH_DIR } from "./config";

export function generateKey(provider: ProviderKey, email: string, keyName: string): void {
  const keyPath = join(SSH_DIR, keyName);

  if (!commandExists("ssh-keygen")) {
    throw new Error("ssh-keygen is required but not found on PATH.");
  }

  const args =
    PROVIDERS[provider].keyType === "rsa"
      ? ["-t", "rsa", "-b", "4096", "-C", email, "-f", keyPath, "-N", ""]
      : ["-t", "ed25519", "-C", email, "-f", keyPath, "-N", ""];

  const result = spawnSync("ssh-keygen", args, { stdio: "inherit", encoding: "utf8" });
  if (result.error) {
    throw result.error;
  }

  if ((result.status ?? 1) !== 0) {
    throw new Error("ssh-keygen failed.");
  }
}

export function readPublicKey(keyName: string): string {
  const publicKeyPath = join(SSH_DIR, `${keyName}.pub`);
  if (!existsSync(publicKeyPath)) {
    throw new Error(`Public key not found: ${publicKeyPath}`);
  }

  return readFileSync(publicKeyPath, "utf8").trim();
}

export function keyExists(keyName: string): boolean {
  return existsSync(join(SSH_DIR, keyName));
}

export function deleteKeyFiles(keyName: string): void {
  const keyPath = join(SSH_DIR, keyName);

  try {
    unlinkSync(keyPath);
  } catch {
    // Ignore missing private key.
  }

  try {
    unlinkSync(`${keyPath}.pub`);
  } catch {
    // Ignore missing public key.
  }
}

import { readFileSync } from "node:fs";
import { spawnSync } from "node:child_process";

export type Platform = "macos" | "linux" | "windows" | "wsl";

export function detectPlatform(): Platform {
  if (process.platform === "win32") {
    return "windows";
  }

  if (process.platform === "darwin") {
    return "macos";
  }

  try {
    const procVersion = readFileSync("/proc/version", "utf8");
    if (procVersion.includes("Microsoft")) {
      return "wsl";
    }
  } catch {
    // Ignore missing /proc/version.
  }

  return "linux";
}

export function commandExists(command: string): boolean {
  const lookup = process.platform === "win32" ? "where" : "which";
  return spawnSync(lookup, [command], { stdio: "ignore" }).status === 0;
}

function tryCopy(text: string, command: string, args: string[] = []): boolean {
  if (!commandExists(command)) {
    return false;
  }

  return spawnSync(command, args, { input: text, encoding: "utf8" }).status === 0;
}

export function copyToClipboard(text: string): boolean {
  const platform = detectPlatform();

  if (platform === "macos") {
    return tryCopy(text, "pbcopy");
  }

  if (platform === "windows") {
    return tryCopy(text, "clip.exe") || tryCopy(text, "clip");
  }

  if (platform === "wsl") {
    return (
      tryCopy(text, "clip.exe") ||
      tryCopy(text, "xclip", ["-selection", "clipboard"]) ||
      tryCopy(text, "xsel", ["--clipboard", "--input"])
    );
  }

  return tryCopy(text, "xclip", ["-selection", "clipboard"]) || tryCopy(text, "xsel", ["--clipboard", "--input"]);
}

function tryOpen(command: string, args: string[]): boolean {
  if (!commandExists(command)) {
    return false;
  }

  return spawnSync(command, args, { stdio: "ignore" }).status === 0;
}

export function openInBrowser(url: string): boolean {
  const platform = detectPlatform();

  if (platform === "macos") {
    return tryOpen("open", [url]);
  }

  if (platform === "windows") {
    return tryOpen("cmd", ["/c", "start", "", url]) || tryOpen("powershell", ["-NoProfile", "-Command", "Start-Process", url]);
  }

  if (platform === "wsl") {
    return tryOpen("cmd.exe", ["/c", "start", "", url]) || tryOpen("powershell.exe", ["-NoProfile", "-Command", "Start-Process", url]) || tryOpen("xdg-open", [url]);
  }

  return tryOpen("xdg-open", [url]);
}

import { copyToClipboard } from "../platform";
import { readPublicKey } from "../ssh/keygen";

export async function copy(keyName: string): Promise<{ publicKey: string; copied: boolean }> {
  const publicKey = readPublicKey(keyName);
  return {
    publicKey,
    copied: copyToClipboard(publicKey),
  };
}

import { join } from "node:path";
import { spawnSync } from "node:child_process";
import { commandExists, detectPlatform } from "../platform";
import { SSH_DIR } from "../ssh/config";

export type AgentKey = {
  fingerprint: string;
  path: string;
  type: string;
};

function ensureAgent(): void {
  if (detectPlatform() === "windows") {
    return;
  }

  if (process.env.SSH_AUTH_SOCK) {
    return;
  }

  if (!commandExists("ssh-agent")) {
    return;
  }

  const result = spawnSync("ssh-agent", ["-s"], { encoding: "utf8" });
  if (result.status !== 0) {
    return;
  }

  for (const match of (result.stdout ?? "").matchAll(/(\w+)=([^;]+);/g)) {
    process.env[match[1]] = match[2];
  }
}

function requireSshAdd(): void {
  if (!commandExists("ssh-add")) {
    throw new Error("ssh-add is required but not found on PATH.");
  }
}

export async function agentList(): Promise<AgentKey[]> {
  requireSshAdd();
  ensureAgent();

  const result = spawnSync("ssh-add", ["-l"], { encoding: "utf8" });
  const output = `${result.stdout ?? ""}${result.stderr ?? ""}`.trim();

  if (result.status === 0 && !output) {
    return [];
  }

  if (result.status === 1 && /no identities/i.test(output)) {
    return [];
  }

  if (result.status !== 0) {
    throw new Error(output || "ssh-add -l failed.");
  }

  return output.split("\n").filter(Boolean).map(line => {
    const parts = line.trim().split(/\s+/);
    return {
      fingerprint: parts[1] ?? "",
      path: parts[2] ?? "",
      type: parts[3] ?? "",
    };
  });
}

export async function agentAdd(keyName: string): Promise<void> {
  requireSshAdd();
  ensureAgent();

  const keyPath = join(SSH_DIR, keyName);
  const args = detectPlatform() === "macos" ? ["--apple-use-keychain", keyPath] : [keyPath];
  const result = spawnSync("ssh-add", args, { encoding: "utf8" });
  if (result.status === 0) {
    return;
  }

  const fallback = spawnSync("ssh-add", [keyPath], { encoding: "utf8" });
  if (fallback.status !== 0) {
    throw new Error((fallback.stderr || fallback.stdout || "ssh-add failed.").trim());
  }
}

export async function agentRemove(keyName: string): Promise<void> {
  requireSshAdd();
  ensureAgent();

  const keyPath = join(SSH_DIR, keyName);
  const result = spawnSync("ssh-add", ["-d", keyPath], { encoding: "utf8" });
  if (result.status !== 0 && !/not found/i.test(`${result.stdout ?? ""}${result.stderr ?? ""}`)) {
    throw new Error((result.stderr || result.stdout || "ssh-add -d failed.").trim());
  }
}

import { join } from "node:path";
import { unlinkSync } from "node:fs";
import { spawnSync } from "node:child_process";
import { commandExists } from "../platform";
import { SSH_DIR, removeManagedHostBlocksForKey } from "../ssh/config";
import { deleteKeyFiles } from "../ssh/keygen";

export async function remove(keyName: string): Promise<{ removedHosts: string[] }> {
  const keyPath = join(SSH_DIR, keyName);

  removeFromAgent(keyPath);
  const removedHosts = removeManagedHostBlocksForKey(keyName);
  deleteKeyFiles(keyName);
  removeGitConfig(keyName);

  return { removedHosts };
}

function removeFromAgent(keyPath: string): void {
  if (!commandExists("ssh-add")) {
    return;
  }

  spawnSync("ssh-add", ["-d", keyPath], { encoding: "utf8" });
}

function removeGitConfig(keyName: string): void {
  const gitConfigPath = join(SSH_DIR, `.gitconfig-${keyName}`);

  try {
    unlinkSync(gitConfigPath);
  } catch {
    // Ignore missing include file.
  }

  if (!commandExists("git")) {
    return;
  }

  const result = spawnSync("git", ["config", "--global", "--get-regexp", "^includeIf\\..*\\.path$"], {
    encoding: "utf8",
  });

  if (result.status !== 0) {
    return;
  }

  const normalizedTargetPath = gitConfigPath.replace(/\\/g, "/");
  for (const line of result.stdout.split("\n").filter(Boolean)) {
    const separatorIndex = line.indexOf(" ");
    if (separatorIndex === -1) {
      continue;
    }

    const key = line.slice(0, separatorIndex);
    const value = line.slice(separatorIndex + 1).trim().replace(/\\/g, "/");
    if (value === normalizedTargetPath) {
      spawnSync("git", ["config", "--global", "--unset", key], { encoding: "utf8" });
    }
  }
}

import { existsSync, mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { homedir } from "node:os";
import { join, normalize } from "node:path";
import { type ProviderKey, PROVIDERS } from "../providers";

export const SSH_DIR = join(homedir(), ".ssh");
export const SSH_CONFIG_PATH = join(SSH_DIR, "config");
export const SSHX_MARKER = "# sshx";

export type ConfigSegment =
  | { kind: "text"; lines: string[] }
  | { kind: "host"; host: string; lines: string[]; managed: boolean };

function isHostStart(line: string): boolean {
  return /^Host\s+/i.test(line) && !/^\s/.test(line);
}

function parseHostName(line: string): string {
  return line.replace(/^Host\s+/i, "").replace(/\s*#.*$/, "").trim();
}

export function parseConfigSegments(content: string): ConfigSegment[] {
  const normalized = content.replace(/\r\n/g, "\n");
  if (!normalized.trim()) {
    return [];
  }

  const lines = normalized.split("\n");
  const segments: ConfigSegment[] = [];
  let textLines: string[] = [];
  let hostLines: string[] | null = null;
  let hostName = "";
  let hostManaged = false;

  const flushText = () => {
    if (textLines.length > 0) {
      segments.push({ kind: "text", lines: [...textLines] });
      textLines = [];
    }
  };

  const flushHost = () => {
    if (hostLines !== null) {
      segments.push({
        kind: "host",
        host: hostName,
        lines: [...hostLines],
        managed: hostManaged,
      });
      hostLines = null;
      hostName = "";
      hostManaged = false;
    }
  };

  for (let index = 0; index < lines.length; index += 1) {
    const line = lines[index]!;
    const next = lines[index + 1];

    if (line.trim() === SSHX_MARKER && next && isHostStart(next)) {
      flushText();
      flushHost();
      hostName = parseHostName(next);
      hostManaged = true;
      hostLines = [line, next];
      index += 1;
      continue;
    }

    if (isHostStart(line)) {
      flushText();
      flushHost();
      hostName = parseHostName(line);
      hostManaged = line.includes(SSHX_MARKER);
      hostLines = [line];
      continue;
    }

    if (hostLines !== null) {
      if (line.trim() === SSHX_MARKER) {
        hostManaged = true;
      }
      hostLines.push(line);
    } else {
      textLines.push(line);
    }
  }

  flushText();
  flushHost();

  return segments;
}

export function serializeConfigSegments(segments: ConfigSegment[]): string {
  const blocks = segments
    .map(segment => segment.lines.join("\n").trimEnd())
    .filter(Boolean);

  if (blocks.length === 0) {
    return "";
  }

  return `${blocks.join("\n\n")}\n`;
}

export function readConfigSegments(): ConfigSegment[] {
  if (!existsSync(SSH_CONFIG_PATH)) {
    return [];
  }

  return parseConfigSegments(readFileSync(SSH_CONFIG_PATH, "utf8"));
}

export function writeConfigSegments(segments: ConfigSegment[]): void {
  mkdirSync(SSH_DIR, { recursive: true });
  writeFileSync(SSH_CONFIG_PATH, serializeConfigSegments(segments));
}

export function extractIdentityFiles(lines: string[]): string[] {
  return lines
    .map(line => line.match(/^\s*IdentityFile\s+(.+)$/i)?.[1]?.trim())
    .filter((value): value is string => Boolean(value))
    .map(value => value.replace(/^"(.*)"$/, "$1"));
}

export function extractHostName(lines: string[]): string {
  const match = lines
    .map(line => line.match(/^\s*HostName\s+(.+)$/i))
    .find(Boolean);

  return match?.[1]?.trim() ?? "";
}

export function expandHomePath(filePath: string): string {
  if (filePath === "~") {
    return homedir();
  }

  if (filePath.startsWith("~/")) {
    return join(homedir(), filePath.slice(2));
  }

  return filePath;
}

export function normalizePath(filePath: string): string {
  return normalize(expandHomePath(filePath)).replace(/\\/g, "/");
}

export function buildHostBlock(provider: ProviderKey, host: string, keyName: string): string[] {
  const lines = [
    SSHX_MARKER,
    `Host ${host}`,
    `  HostName ${PROVIDERS[provider].hostname}`,
    "  User git",
    "  AddKeysToAgent yes",
    `  IdentityFile ~/.ssh/${keyName}`,
    "  IdentitiesOnly yes",
  ];

  if (provider === "azure") {
    lines.push("  HostkeyAlgorithms +ssh-rsa");
    lines.push("  PubkeyAcceptedAlgorithms +ssh-rsa");
  }

  return lines;
}

export function findHostBlock(host: string): Extract<ConfigSegment, { kind: "host" }> | undefined {
  return readConfigSegments().find(
    (segment): segment is Extract<ConfigSegment, { kind: "host" }> => segment.kind === "host" && segment.host === host,
  );
}

export function upsertHostBlock(provider: ProviderKey, host: string, keyName: string): "added" | "replaced" {
  const segments = readConfigSegments();
  const replacement: ConfigSegment = {
    kind: "host",
    host,
    lines: buildHostBlock(provider, host, keyName),
    managed: true,
  };

  let replaced = false;
  const nextSegments = segments.map(segment => {
    if (segment.kind === "host" && segment.host === host) {
      replaced = true;
      return replacement;
    }

    return segment;
  });

  if (!replaced) {
    nextSegments.push(replacement);
  }

  writeConfigSegments(nextSegments);
  return replaced ? "replaced" : "added";
}

export function removeManagedHostBlocksForKey(keyName: string): string[] {
  const keyPathVariants = new Set([
    normalizePath(join(SSH_DIR, keyName)),
    normalizePath(`~/.ssh/${keyName}`),
    normalizePath(keyName),
  ]);

  const removedHosts: string[] = [];
  const nextSegments = readConfigSegments().filter(segment => {
    if (segment.kind !== "host" || !segment.managed) {
      return true;
    }

    const matchesKey = extractIdentityFiles(segment.lines).some(identityFile =>
      keyPathVariants.has(normalizePath(identityFile)),
    );

    if (matchesKey) {
      removedHosts.push(segment.host);
      return false;
    }

    return true;
  });

  writeConfigSegments(nextSegments);
  return removedHosts;
}

export function listManagedHostBlocks(): Array<{
  host: string;
  hostname: string;
  identityFiles: string[];
}> {
  return readConfigSegments()
    .filter((segment): segment is Extract<ConfigSegment, { kind: "host" }> => segment.kind === "host" && segment.managed)
    .map(segment => ({
      host: segment.host,
      hostname: extractHostName(segment.lines) || segment.host,
      identityFiles: extractIdentityFiles(segment.lines),
    }));
}

import { spawnSync } from "node:child_process";
import { commandExists } from "../platform";
import { type ProviderKey, PROVIDERS } from "../providers";

export type TestResult = {
  success: boolean;
  output: string;
};

export async function testConnection(provider: ProviderKey): Promise<TestResult> {
  if (!commandExists("ssh")) {
    throw new Error("ssh is required but not found on PATH.");
  }

  const hostname = PROVIDERS[provider].hostname;
  const result = spawnSync(
    "ssh",
    [
      "-T",
      "-o",
      "StrictHostKeyChecking=accept-new",
      "-o",
      "BatchMode=yes",
      `git@${hostname}`,
    ],
    { encoding: "utf8" },
  );

  const output = `${result.stdout ?? ""}${result.stderr ?? ""}`.trim();
  const successPattern = /successfully authenticated|shell access is not supported|authenticated/i;
  const success = result.status === 0 || result.status === 1 || successPattern.test(output);

  return { success, output };
}

