  }

  process.stderr.write(`Unknown command: ${command}\nRun "sshx --help" for usage.\n`);
  process.exit(1);
}

main().catch(error => {
  process.stderr.write(`Error: ${error instanceof Error ? error.message : String(error)}\n`);
  process.exit(1);
});

import React from "react";
import { Box, CustomSelect, Text } from "@vancityayush/tui";
import { Header } from "../components/Header";

export type MainMenuAction = "setup" | "key-list" | "test-connection" | "agent";

const MENU_OPTIONS: Array<{ label: string; value: MainMenuAction; description: string }> = [
  {
    label: "Setup new key",
    value: "setup",
    description: "Generate a new SSH key and configure a provider host.",
  },
  {
    label: "List / manage keys",
    value: "key-list",
    description: "Copy or remove managed SSH keys.",
  },
  {
    label: "Test connection",
    value: "test-connection",
    description: "Run ssh -T against a provider host.",
  },
  {
    label: "SSH agent",
    value: "agent",
    description: "See which keys are loaded and add or remove them.",
  },
];

type Props = {
  onSelect: (action: MainMenuAction) => void;
};

export function MainMenu({ onSelect }: Props): React.ReactNode {
  return (
    <Box flexDirection="column">
      <Header subtitle="Select an action" />
      <CustomSelect
        options={MENU_OPTIONS}
        onChange={value => onSelect(value)}
        visibleOptionCount={4}
      />
      <Box marginTop={1}>
        <Text dimColor>Enter select · q exit</Text>
      </Box>
    </Box>
  );
}

import React, { useState } from "react";
import { Box, CustomSelect, Spinner, Text, useInput } from "@vancityayush/tui";
import { testConnection, type TestResult } from "../../commands/test";
import { PROVIDER_KEYS, PROVIDERS, type ProviderKey } from "../../providers";
import { Header } from "../components/Header";

type Props = {
  onBack: () => void;
};

type Phase = "select" | "testing" | "result";

const PROVIDER_OPTIONS = PROVIDER_KEYS.map(key => ({
  label: PROVIDERS[key].label,
  value: key,
  description: `ssh -T git@${PROVIDERS[key].hostname}`,
}));

export function TestConnection({ onBack }: Props): React.ReactNode {
  const [phase, setPhase] = useState<Phase>("select");
  const [provider, setProvider] = useState<ProviderKey>("github");
  const [result, setResult] = useState<TestResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  useInput((_input, key) => {
    if (!key.escape || phase === "testing") {
      return;
    }

    if (phase === "result") {
      setPhase("select");
      setResult(null);
      setError(null);
      return;
    }

    onBack();
  });

  async function runTest(nextProvider: ProviderKey): Promise<void> {
    setProvider(nextProvider);
    setPhase("testing");
    setResult(null);
    setError(null);

    try {
      setResult(await testConnection(nextProvider));
    } catch (testError) {
      setError(testError instanceof Error ? testError.message : String(testError));
    } finally {
      setPhase("result");
    }
  }

  if (phase === "select") {
    return (
      <Box flexDirection="column">
        <Header subtitle="Select a provider to test" />
        <CustomSelect
          options={PROVIDER_OPTIONS}
          defaultValue={provider}
          onCancel={onBack}
          onChange={value => {
            void runTest(value);
          }}
          visibleOptionCount={4}
        />
        <Box marginTop={1}>
          <Text dimColor>Esc back</Text>
        </Box>
      </Box>
    );
  }

  if (phase === "testing") {
    return (
      <Box flexDirection="column">
        <Header subtitle={`Testing ${PROVIDERS[provider].label}`} />
        <Spinner label={`ssh -T git@${PROVIDERS[provider].hostname}`} />
      </Box>
    );
  }

  return (
    <Box flexDirection="column" gap={1}>
      <Header subtitle={`Result for ${PROVIDERS[provider].label}`} />
      {error ? <Text color="red">{error}</Text> : null}
      {result ? (
        <>
          <Text color={result.success ? "green" : "red"}>
            {result.success ? "Connection looks good." : "Connection test failed."}
          </Text>
          {result.output ? (
            <>
              <Text dimColor>Output</Text>
              <Text>{result.output}</Text>
            </>
          ) : null}
        </>
      ) : null}
      <Text dimColor>Esc choose another provider · Esc again back</Text>
    </Box>
  );
}

import React, { useEffect, useState } from "react";
import { Box, Dialog, ListItem, Spinner, Text, useInput } from "@vancityayush/tui";
import { copy } from "../../commands/copy";
import { list, type ManagedKey } from "../../commands/list";
import { remove } from "../../commands/remove";
import { PROVIDERS } from "../../providers";
import { Header } from "../components/Header";

type Props = {
  onBack: () => void;
};

export function KeyList({ onBack }: Props): React.ReactNode {
  const [keys, setKeys] = useState<ManagedKey[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [confirmRemove, setConfirmRemove] = useState<string | null>(null);
  const [status, setStatus] = useState<string | null>(null);

  async function refresh(): Promise<void> {
    try {
      const nextKeys = await list();
      setKeys(nextKeys);
      setSelectedIndex(currentIndex => (nextKeys.length === 0 ? 0 : Math.min(currentIndex, nextKeys.length - 1)));
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    void refresh();
  }, []);

  useInput((input, key) => {
    if (loading) {
      return;
    }

    if (confirmRemove) {
      if (key.escape) {
        setConfirmRemove(null);
      } else if (key.return) {
        void handleRemove(confirmRemove);
      }
      return;
    }

    if (key.escape) {
      onBack();
      return;
    }

    if (keys.length === 0) {
      return;
    }

    if (key.upArrow) {
      setSelectedIndex(index => Math.max(0, index - 1));
      return;
    }

    if (key.downArrow) {
      setSelectedIndex(index => Math.min(keys.length - 1, index + 1));
      return;
    }

    const currentKey = keys[selectedIndex];
    if (!currentKey) {
      return;
    }

    if (key.return) {
      void handleCopy(currentKey.name);
      return;
    }

    if (input === "d") {
      setConfirmRemove(currentKey.name);
    }
  });

  async function handleCopy(name: string): Promise<void> {
    try {
      const result = await copy(name);
      setStatus(result.copied ? `Copied ${name} to clipboard.` : result.publicKey);
    } catch (copyError) {
      setStatus(copyError instanceof Error ? copyError.message : String(copyError));
    }
  }

  async function handleRemove(name: string): Promise<void> {
    setConfirmRemove(null);
    try {
      await remove(name);
      setStatus(`Removed ${name}.`);
      await refresh();
    } catch (removeError) {
      setStatus(removeError instanceof Error ? removeError.message : String(removeError));
    }
  }

  if (loading) {
    return (
      <Box flexDirection="column">
        <Header subtitle="Managed keys" />
        <Spinner label="Loading managed SSH keys..." />
      </Box>
    );
  }

  return (
    <Box flexDirection="column">
      <Header subtitle={`${keys.length} managed key${keys.length === 1 ? "" : "s"}`} />

      {keys.length === 0 ? <Text dimColor>No managed keys found. Run setup first.</Text> : null}

      {keys.map((key, index) => (
        <ListItem
          key={`${key.host}-${key.name}`}
          isFocused={index === selectedIndex}
          isSelected={index === selectedIndex}
          description={`${key.host} · ${key.provider ? PROVIDERS[key.provider].label : "Unknown provider"}`}
        >
          {key.name}
        </ListItem>
      ))}

      {status ? (
        <Box marginTop={1}>
          <Text dimColor>{status}</Text>
        </Box>
      ) : null}

      <Box marginTop={1}>
        <Text dimColor>↑↓ navigate · Enter copy · d remove · Esc back</Text>
      </Box>

      {confirmRemove ? (
        <Dialog
          title={`Remove "${confirmRemove}"?`}
          subtitle="This deletes the key files, managed SSH config block, and per-key git include."
          onCancel={() => setConfirmRemove(null)}
        >
          <Text>Press Enter to confirm or Esc to cancel.</Text>
        </Dialog>
      ) : null}
    </Box>
  );
}

import React, { useEffect, useState } from "react";
import { Box, CustomSelect, Spinner, Text, TextInput, useInput } from "@vancityayush/tui";
import { readGitContext, setup, type SetupResult } from "../../commands/setup";
import { PROVIDER_KEYS, PROVIDERS, type ProviderKey } from "../../providers";
import { Header } from "../components/Header";

type WizardStep = "provider" | "email" | "keyname" | "result";

type Props = {
  onBack: () => void;
};

const INPUT_COLUMNS = 52;
const PROVIDER_OPTIONS = PROVIDER_KEYS.map(key => ({
  label: PROVIDERS[key].label,
  value: key,
  description: PROVIDERS[key].hostname,
}));

export function Setup({ onBack }: Props): React.ReactNode {
  const [step, setStep] = useState<WizardStep>("provider");
  const [provider, setProvider] = useState<ProviderKey>("github");
  const [email, setEmail] = useState("");
  const [emailCursor, setEmailCursor] = useState(0);
  const [keyName, setKeyName] = useState("");
  const [keyNameCursor, setKeyNameCursor] = useState(0);
  const [generating, setGenerating] = useState(false);
  const [result, setResult] = useState<SetupResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const gitContext = readGitContext();
    if (gitContext.provider) {
      setProvider(gitContext.provider);
    }
    if (gitContext.email) {
      setEmail(gitContext.email);
      setEmailCursor(gitContext.email.length);
    }
  }, []);

  useEffect(() => {
    const defaultKeyName = `id_${PROVIDERS[provider].keyType}_${provider}`;
    setKeyName(defaultKeyName);
    setKeyNameCursor(defaultKeyName.length);
  }, [provider]);

  useInput((_input, key) => {
    if (!key.escape || generating) {
      return;
    }

    if (step === "provider") {
      onBack();
      return;
    }

    if (step === "email") {
      setStep("provider");
      return;
    }

    if (step === "keyname") {
      setStep("email");
      return;
    }

    onBack();
  });

  async function runSetup(): Promise<void> {
    if (!email.trim()) {
      setError("Email is required.");
      setStep("result");
      return;
    }

    if (!keyName.trim()) {
      setError("Key name is required.");
      setStep("result");
      return;
    }

    setGenerating(true);
    setResult(null);
    setError(null);
    setStep("result");

    try {
      const nextResult = await setup({
        provider,
        email: email.trim(),
        keyName: keyName.trim(),
      });
      setResult(nextResult);
    } catch (setupError) {
      setError(setupError instanceof Error ? setupError.message : String(setupError));
    } finally {
      setGenerating(false);
    }
  }

  if (step === "provider") {
    return (
      <Box flexDirection="column">
        <Header subtitle="Step 1 of 3: choose a provider" />
        <CustomSelect
          options={PROVIDER_OPTIONS}
          defaultValue={provider}
          onCancel={onBack}
          onChange={value => {
            setProvider(value);
            setStep("email");
          }}
          visibleOptionCount={4}
        />
        <Box marginTop={1}>
          <Text dimColor>Esc back</Text>
        </Box>
      </Box>
    );
  }

  if (step === "email") {
    return (
      <Box flexDirection="column" gap={1}>
        <Header subtitle="Step 2 of 3: email comment" />
        <Text>Email</Text>
        <TextInput
          value={email}
          onChange={setEmail}
          onSubmit={value => {
            if (value.trim()) {
              setStep("keyname");
            }
          }}
          onExit={() => setStep("provider")}
          placeholder="you@example.com"
          focus
          showCursor
          columns={INPUT_COLUMNS}
          cursorOffset={emailCursor}
          onChangeCursorOffset={setEmailCursor}
        />
        <Text dimColor>Enter continue · Esc back</Text>
      </Box>
    );
  }

  if (step === "keyname") {
    return (
      <Box flexDirection="column" gap={1}>
        <Header subtitle="Step 3 of 3: key file name" />
        <Text>Key name</Text>
        <TextInput
          value={keyName}
          onChange={setKeyName}
          onSubmit={value => {
            if (value.trim()) {
              void runSetup();
            }
          }}
          onExit={() => setStep("email")}
          placeholder={`id_${PROVIDERS[provider].keyType}_${provider}`}
          focus
          showCursor
          columns={INPUT_COLUMNS}
          cursorOffset={keyNameCursor}
          onChangeCursorOffset={setKeyNameCursor}
        />
        <Text dimColor>Enter generate · Esc back</Text>
      </Box>
    );
  }

  if (generating) {
    return (
      <Box flexDirection="column">
        <Header subtitle="Generating key and updating SSH config" />
        <Spinner label={`Generating ${PROVIDERS[provider].keyType} key for ${PROVIDERS[provider].label}...`} />
      </Box>
    );
  }

  return (
    <Box flexDirection="column" gap={1}>
      <Header subtitle={error ? "Setup failed" : "Setup complete"} />
      {error ? <Text color="red">{error}</Text> : null}
      {result ? (
        <>
          <Text color="green">Created ~/.ssh/{result.keyName}</Text>
          <Text color="green">Updated SSH config for {result.host}</Text>
          {result.clipboardCopied ? (
            <Text color="green">Copied the public key to your clipboard.</Text>
          ) : (
            <Text dimColor>Clipboard copy was unavailable. Paste the key manually.</Text>
          )}
          {result.browserOpened ? (
            <Text color="green">Opened the provider SSH keys page.</Text>
          ) : (
            <Text dimColor>Browser open was unavailable.</Text>
          )}
          <Text dimColor>Public key</Text>
          <Text>{result.publicKey}</Text>
        </>
      ) : null}
      <Text dimColor>Esc return to menu</Text>
    </Box>
  );
}

import React, { useState } from "react";
import { Box, useApp, useInput } from "@vancityayush/tui";
import { MainMenu, type MainMenuAction } from "./screens/MainMenu";
import { Agent } from "./screens/Agent";
import { KeyList } from "./screens/KeyList";
import { Setup } from "./screens/Setup";
import { TestConnection } from "./screens/TestConnection";

type Screen = "main-menu" | MainMenuAction;

export function App(): React.ReactNode {
  const { exit } = useApp();
  const [screen, setScreen] = useState<Screen>("main-menu");

  useInput((input, key) => {
    if (screen === "main-menu" && ((key.ctrl && input === "c") || input === "q")) {
      exit();
    }
  });

  const goBack = () => setScreen("main-menu");

  return (
    <Box flexDirection="column" paddingX={1} paddingY={1}>
      {screen === "main-menu" ? <MainMenu onSelect={action => setScreen(action)} /> : null}
      {screen === "setup" ? <Setup onBack={goBack} /> : null}
      {screen === "key-list" ? <KeyList onBack={goBack} /> : null}
      {screen === "test-connection" ? <TestConnection onBack={goBack} /> : null}
      {screen === "agent" ? <Agent onBack={goBack} /> : null}
    </Box>
  );
}

