    "$PackageName@$Version"
} else {
    $PackageName
}

$BinDir = Join-Path $Prefix "bin"
Write-Host "Installing $PackageSpec under $Prefix"
& npm install -g --prefix $Prefix $PackageSpec

if (-not $NoRun) {
    Write-Host ""
    Write-Host "Launching sshx..."
    & (Join-Path $BinDir "sshx.cmd") @SshxArgs
    exit $LASTEXITCODE
}

